INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('helmuth', '{"name":"Helmuth","mapped_name":null,"birth_date":"1988-04-30","profession":"Diretor Executivo","sports_history":"Helmuth: Quando mais jovem praticou musculação (há mais de 10 anos), após entrar na faculdade ficou difícil conciliar, ano passado ficou um ano na vida \"fit\", perdeu 12kg em aprox 3~4 meses. Fazia treinos \"HIIT\" e no app da Apple.\nCurtia treinar musculação. Prioridade é perder peso.\nAcademia muito cheia e o instrutor não dava muito atenção.\n\n\nCibele: também treinou há algum tempo atrás, (mãe de 2), treinava em casa cuidando da alimentação e conseguiu perder bastante peso no período. Quando a filha começou a escolinha conseguiu se manter quase 2 anos treinando direto na academia.","injuries":["H: nada","excelente.","C: nada","excelente."],"health_conditions":["Nada."],"medications":["H: Remédio pro colesterol. Nebloc (coração","diminuição do ritmo cardíaco)","zoopiden e donaren esporadicamente.","C: nada."],"current_practice":"H: 1 ano parado, e esteve fazendo HIIT desde o início da pandemia. Musculação não faz há 1 ano também.\n\nC: treinou reuglharmente até novembro, desde o início da pandemia. 2 meses parada.","goal":"H: ser mais disciplinado, estar mais vinculado com um estilo de vida saudável. Saúde.\n\nC: busca desenvolver mais a musculatura aliada a definição.","weekly_frequency":null,"session_duration":null,"gender":"M","experience_level":"intermediário","form_timestamp":"2022/02/02 1:36:42 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Puxada Frente Supinada","method":"Tradicional 6-8","sets":"","reps":"","interval":"2''","observations":"Palma das mãos para trás para ter mais auxílio do bíceps."},{"name":"Remada Serrote Halteres","method":"Tradicional 10 Cada braço","sets":"","reps":"10 Cada Braço","interval":"1''30\"","observations":""},{"name":"Levantamento Terra","method":"Tradicional 5-7","sets":"","reps":"5-7 repetições","interval":"1''30\"","observations":"Usar a barra reta, iniciar o movimento com a barra no chão, aprox. no meio das canelas. Levantar com a coluna reta e a barra rente ao corpo até a altura do quadril."},{"name":"Rosca Scott Barra","method":"Tradicional\n8 a 10","sets":"","reps":"8 - 10","interval":"1''30\"","observations":""}]},"B":{"focus":"","exercises":[{"name":"Supino Inclinado Barra","method":"Tradicional 8-10","sets":"","reps":"","interval":"2''","observations":"Descer a barra até no máximo a altura do queixo, não precisa encostar no peito."},{"name":"Crucifixo Máquina","method":"Tradicional \n8-10","sets":"","reps":"","interval":"1''30\"","observations":"X"},{"name":"Cadeira Flexora","method":"Tradicional 8-12","sets":"","reps":"","interval":"1''30\"","observations":"Manter a coluna reta durante toda a execução do exercício"},{"name":"Cadeira Extensora","method":"Tradicional 8-12","sets":"","reps":"","interval":"1''30\"","observations":"Realizar 8 reps, diminuir o peso e fazer mais 8 para acumular mais volume de treino de tríceps"}]},"C":{"focus":"","exercises":[{"name":"Supino Reto Barra","method":"Tradicional 8-10","sets":"","reps":"","interval":"2''","observations":""},{"name":"Desenvolvimento de Ombros Halteres + Elevação Lateral","method":"Bi-Set \n8+10","sets":"","reps":"8+10","interval":"1''30\"","observations":"X"},{"name":"Leg Press","method":"Tradicional 8-10","sets":"","reps":"","interval":"1''30\"","observations":"Usar o banco inclinado com o suporte da barra, chegar próximo a linha do queixo e subir a barra completando cada repetição"},{"name":"Tríceps Barra no Crossover","method":"DropSet\n8+8","sets":"","reps":"","interval":"1''30\"","observations":"Realizar 8 reps, diminuir o peso e fazer mais 8 para acumular mais volume de treino de tríceps"}]}}'::jsonb, ARRAY['A','B','C']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split